SELECT PP.*, '' AS valor_unico 
                                             FROM producto_parametros PP 
                                             WHERE PP.IdProducto={0} 
                                             AND PP.activo={1}

SELECT {0} Estado, SUM(Cantidad) AS Cantidad 
                                    FROM VW_ESTADO_ENVIOS_NAV 
                                    WHERE FECHA BETWEEN {1} AND {2} {3}
                                    GROUP BY ESTADO{4}

DELETE from trans_manufactura_det 
                                  WHERE IdManufacturaEnc IN (SELECT IdManufacturaEnc FROM trans_manufactura_enc WHERE IdPedidoEnc =  @IdPedidoEnc);
                                  DELETE FROM trans_manufactura_enc WHERE IdPedidoEnc =  @IdPedidoEnc;
